```verilog
module t (
   input clk
 );

  function automatic logic foo(logic bar);
    foo = '0;
  endfunction

  logic a, b, res;
  logic [0:0][1:0] array;
 
  assign b = 0;
  assign a = foo(b);
  assign res = array[a][a]; 

endmodule
```

